from solution import solve

def test_cycle_and_leaf_neighbor():
    assert solve({'a': ['b'], 'b': ['c'], 'c': ['a']}) is True
    assert solve({'a': ['missing']}) is False

def test_empty_graph():
    assert solve({}) is False
